export const NA = 6.02214076e23;
export const RO_CM = 140e-10;

export function parseFormula(formula) {
  const regex = /([A-Z][a-z]?)(\d*)/g;
  const elements = [];
  let match;
  while ((match = regex.exec(formula)) !== null) {
    if (match[1]) {
      elements.push({
        element: match[1],
        count: match[2] ? parseInt(match[2], 10) : 1,
      });
    }
  }
  return elements;
}

export function getMolecularWeight(formula) {
  const elements = parseFormula(formula);
  return elements.reduce((sum, { element, count }) => {
    const w = ATOMIC_WEIGHTS[element];
    if (w === undefined) {
      throw new Error(`Unknown element: ${element}`);
    }
    return sum + w * count;
  }, 0);
}

export function getCationAndOxygen(formula) {
  const elements = parseFormula(formula);
  const oxygenEntry = elements.find((e) => e.element === "O");
  if (!oxygenEntry) {
    throw new Error("FORMULA_NO_OXYGEN");
  }
  const cationEntry = elements.find((e) => e.element !== "O");
  if (!cationEntry) {
    throw new Error("FORMULA_NO_CATION");
  }
  return {
    cation: cationEntry.element,
    n: cationEntry.count,
    m: oxygenEntry.count,
  };
}

export function resolveOxidationState(cation, n, m) {
  const ox = (m * 2) / n;
  return Math.round(ox);
}

export function getCationRadius(cation, oxidation) {
  const radii = IONIC_RADII[cation];
  if (!radii) {
    throw new Error(`No ionic radius data for: ${cation}`);
  }
  const r = radii[String(oxidation)];
  if (r !== undefined) {
    return r;
  }
  const available = Object.keys(radii).map(Number);
  const closest = available.reduce((a, b) =>
    Math.abs(b - oxidation) < Math.abs(a - oxidation) ? b : a
  );
  return radii[String(closest)];
}

export function calculate(compounds) {
  const totalCoeff = compounds.reduce((s, c) => s + c.coefficient, 0);

  const processed = compounds.map((c) => {
    const MW = getMolecularWeight(c.formula);
    const xi = c.coefficient / totalCoeff;
    const { cation, n, m } = getCationAndOxygen(c.formula);
    const oxidation = resolveOxidationState(cation, n, m);
    const R_pm = getCationRadius(cation, oxidation);
    const R_cm = R_pm * 1e-10;
    const Ui_kJ = c.bde_kcal * 4.184;

    const Vi =
      (4 * Math.PI) / 3 * NA * (n * R_cm ** 3 + m * RO_CM ** 3);

    const Gi = (c.density / MW) * Ui_kJ;

    return {
      formula: c.formula,
      MW,
      xi,
      cation,
      oxidation,
      n,
      m,
      R_pm,
      Vi,
      Ui_kJ,
      Gi,
      density: c.density,
    };
  });

  const Vm = processed.reduce((s, c) => s + (c.xi * c.MW) / c.density, 0);

  const sumXiVi = processed.reduce((s, c) => s + c.xi * c.Vi, 0);
  const Vt = sumXiVi / Vm;

  const Gt = processed.reduce((s, c) => s + c.Gi * c.xi, 0);

  const E = 8.36 * Vt * Gt;
  const K = 10.0 * Vt * Vt * Gt;
  const S = (3 * K) / (10.2 * Vt - 1);
  const L = K + (4 * S) / 3;
  const nu = 0.5 - 1 / (7.2 * Vt);

  return {
    summary: {
      total_coefficient: totalCoeff,
      sumXiVi,
      Vm,
      Vt,
      Gt,
      E,
      K,
      S,
      L,
      nu,
    },
    compounds: processed,
  };
}
